diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index a4b0378abc07..7d9c2da82761 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -3560,8 +3560,14 @@ private:
     /// elements, forming whole vectors.
     bool
     hasNonWholeRegisterOrNonPowerOf2Vec(const TargetTransformInfo &TTI) const {
+      Type *ValueType = getValueType(Scalars.front());
+      // For invalid element types like x86_fp80, we don't need to check
+      // the reshuffling constraint since these types are not vectorized.
+      if (!isValidElementType(ValueType)) {
+        return false; // These types are scalarized, so no non-power-of-2 issue
+      }
       bool IsNonPowerOf2 = !hasFullVectorsOrPowerOf2(
-          TTI, getValueType(Scalars.front()), Scalars.size());
+          TTI, ValueType, Scalars.size());
       assert((!IsNonPowerOf2 || ReuseShuffleIndices.empty()) &&
              "Reshuffling not supported with non-power-of-2 vectors yet.");
       return IsNonPowerOf2;
@@ -3706,10 +3712,17 @@ private:
     TreeEntry *Last = VectorizableTree.back().get();
     Last->Idx = VectorizableTree.size() - 1;
     Last->State = EntryState;
+    Type *ValueType = getValueType(VL.front());
+    // For invalid element types like x86_fp80, we allow reshuffling since
+    // these types are not vectorized anyway.
+    if (!isValidElementType(ValueType)) {
+      // Clear ReuseShuffleIndices for invalid element types to avoid assertion
+      ReuseShuffleIndices = {};
+    }
     // FIXME: Remove once support for ReuseShuffleIndices has been implemented
     // for non-power-of-two vectors.
     assert(
-        (hasFullVectorsOrPowerOf2(*TTI, getValueType(VL.front()), VL.size()) ||
+        (hasFullVectorsOrPowerOf2(*TTI, ValueType, VL.size()) ||
          ReuseShuffleIndices.empty()) &&
         "Reshuffling scalars not yet supported for nodes with padding");
     Last->ReuseShuffleIndices.append(ReuseShuffleIndices.begin(),
@@ -8852,9 +8865,18 @@ void BoUpSLP::buildTree_rec(ArrayRef<Value *> VL, unsigned Depth,
       ReuseShuffleIndices.clear();
     } else {
       // FIXME: Reshuffing scalars is not supported yet for non-power-of-2 ops.
+      Type *ValueType = VL.front()->getType();
+      if (!isValidElementType(ValueType)) {
+        // For invalid element types like x86_fp80, skip the reshuffling check
+        // and proceed with gathering.
+        LLVM_DEBUG(dbgs() << "SLP: Skipping reshuffling check for invalid element type.\n");
+        auto Invalid = ScheduleBundle::invalid();
+        newTreeEntry(VL, Invalid /*not vectorized*/, S, UserTreeIdx);
+        return false;
+      }
       if ((UserTreeIdx.UserTE &&
            UserTreeIdx.UserTE->hasNonWholeRegisterOrNonPowerOf2Vec(*TTI)) ||
-          !hasFullVectorsOrPowerOf2(*TTI, VL.front()->getType(), VL.size())) {
+          !hasFullVectorsOrPowerOf2(*TTI, ValueType, VL.size())) {
         LLVM_DEBUG(dbgs() << "SLP: Reshuffling scalars not yet supported "
                              "for nodes with padding.\n");
         auto Invalid = ScheduleBundle::invalid();

